const now = Date.now();
const dedupeMs = 900;
let action;

if (typeof msg.payload === 'string') {
    action = msg.payload;
} else if (msg.payload && typeof msg.payload === 'object') {
    action = msg.payload.action;
}

if (action !== 'single') {
    return null;
}

const lastAccepted = Number(flow.get('portao_garagem_last_click_ms') || 0);
if (now - lastAccepted < dedupeMs) {
    return null;
}

flow.set('portao_garagem_last_click_ms', now);
msg.payload = {
    action,
    source_topic: msg.topic,
    received_at: new Date(now).toISOString(),
};
msg.portao_retry_count = 0;
return msg;

const expected = msg.expected_state || msg.payload?.expected_state;
const labels = {
    lampada_varanda: 'varanda',
    lampadas_garagem: 'garagem',
    refletores_jardim: 'jardim'
};
const states = {
    lampada_varanda: msg.payload?.lampada_varanda,
    lampadas_garagem: msg.payload?.lampadas_garagem,
    refletores_jardim: msg.payload?.refletores_jardim
};
const failed = Object.entries(states)
    .filter(([, state]) => state !== expected)
    .map(([entity, state]) => `${labels[entity]} ${state || 'desconhecido'}`);

if (failed.length === 0) {
    msg.notify_text = msg.notify_success || msg.notify_text;
    return msg;
}

const expectedText = expected === 'on' ? 'ligada' : 'desligada';
msg.notify_text = `Erro ao acionar a iluminação externa. Esperado: ${expectedText}. Estado atual: ${failed.join(', ')}.`;
return msg;

const getState = (value) => {
    if (value === undefined || value === null) return undefined;
    if (typeof value === "string") return value;
    if (typeof value === "object" && value.state !== undefined) return value.state;
    return undefined;
};

// "unknown"/"unavailable" sao glitches momentaneos da integracao moni_mobile
// (falha de parsing no protocolo TCP) e nao devem contar como estado real,
// nem entrar no historico usado para detectar mudanca.
const isUnknown = (state) =>
    state === undefined ||
    state === null ||
    state === "" ||
    state === "unknown" ||
    state === "unavailable";

const data = msg.data?.event ?? msg.data ?? {};

const oldStateRaw =
    getState(data.old_state) ??
    getState(msg.old_state);

const newState =
    getState(data.new_state) ??
    getState(msg.new_state) ??
    getState(msg.payload);

const entityId =
    data.entity_id ??
    msg.topic ??
    "alarm_control_panel.alarme_moni_mobile";

const cacheKey = `last_alarm_state:${entityId}`;

if (!newState) {
    node.status({
        fill: "red",
        shape: "ring",
        text: "sem estado novo"
    });
    return null;
}

if (isUnknown(newState)) {
    node.status({
        fill: "grey",
        shape: "ring",
        text: `ignorado: ${newState}`
    });
    return null;
}

// Se o old_state vindo do evento for "unknown", usa o ultimo estado real
// salvo no flow context em vez de tratar o glitch como estado anterior.
const lastState = !isUnknown(oldStateRaw) ? oldStateRaw : flow.get(cacheKey);

flow.set(cacheKey, newState);

if (lastState === newState) {
    node.status({
        fill: "grey",
        shape: "ring",
        text: `bloqueado: ${lastState} -> ${newState}`
    });
    return null;
}

msg.previous_alarm_state = lastState ?? "desconhecido";
msg.current_alarm_state = newState;
msg.alarm_state_changed = true;

node.status({
    fill: "green",
    shape: "dot",
    text: `${lastState ?? "?"} -> ${newState}`
});

return msg;

const attempt = Number(msg.arm_alarm_retry_count || 0) + 1;
msg.arm_alarm_retry_count = attempt;
const errorMessage = msg.error?.message || msg.error?.source?.name || 'erro desconhecido';

node.status({ fill: "yellow", shape: "dot", text: `tentativa ${attempt}: ${errorMessage}` });
node.warn(`Erro ao armar o alarme (tentativa ${attempt}): ${errorMessage}. Nova tentativa em instantes.`);

// Avisa no primeiro erro e depois a cada 5 tentativas para nao spammar o Alexa
// enquanto o dispositivo moni_mobile estiver offline.
if (attempt === 1 || attempt % 5 === 0) {
    msg.notify_text = attempt === 1
        ? 'Não foi possível armar o alarme: dispositivo offline. Tentando novamente...'
        : `Ainda tentando armar o alarme (tentativa ${attempt}). Dispositivo continua offline.`;
    return [msg, msg];
}
return [msg, null];

const attempt = Number(msg.disarm_alarm_retry_count || 0) + 1;
msg.disarm_alarm_retry_count = attempt;
const errorMessage = msg.error?.message || msg.error?.source?.name || 'erro desconhecido';

node.status({ fill: "yellow", shape: "dot", text: `tentativa ${attempt}: ${errorMessage}` });
node.warn(`Erro ao desarmar o alarme (tentativa ${attempt}): ${errorMessage}. Nova tentativa em instantes.`);

// Avisa no primeiro erro e depois a cada 5 tentativas para nao spammar o Alexa
// enquanto o dispositivo moni_mobile estiver offline.
if (attempt === 1 || attempt % 5 === 0) {
    msg.notify_text = attempt === 1
        ? 'Não foi possível desarmar o alarme: dispositivo offline. Tentando novamente...'
        : `Ainda tentando desarmar o alarme (tentativa ${attempt}). Dispositivo continua offline.`;
    return [msg, msg];
}
return [msg, null];

const HOME_LAT = -20.310367851039004;
const HOME_LON = -40.317321761139894;
const ARM_DISTANCE_M = 100;
const MAX_GPS_ACCURACY_M = 100;
const KIA_REFRESH_INTERVAL_MS = 5 * 60 * 1000;
const KIA_NEARBY_DISTANCE_M = 1500;
const KIA_LAST_REFRESH_KEY = "sec_kia_last_force_refresh_ts";

function distanceMeters(lat1, lon1, lat2, lon2) {
    const toRad = (value) => value * Math.PI / 180;
    const dLat = toRad(lat2 - lat1);
    const dLon = toRad(lon2 - lon1);
    const a = Math.sin(dLat / 2) ** 2 +
        Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
        Math.sin(dLon / 2) ** 2;
    return 6371000 * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

function distanceFromHome(entity) {
    const attrs = entity?.attributes ?? {};
    const lat = Number(attrs.latitude);
    const lon = Number(attrs.longitude);
    const gpsAccuracy = Number(attrs.gps_accuracy);
    const hasCoordinates = Number.isFinite(lat) && Number.isFinite(lon);
    const hasGpsAccuracy = Number.isFinite(gpsAccuracy);
    const reliableCoordinates = hasCoordinates && (!hasGpsAccuracy || gpsAccuracy <= MAX_GPS_ACCURACY_M);
    return reliableCoordinates ? Math.round(distanceMeters(HOME_LAT, HOME_LON, lat, lon)) : null;
}

function reliableCoords(entity) {
    const attrs = entity?.attributes ?? {};
    const lat = Number(attrs.latitude);
    const lon = Number(attrs.longitude);
    const gpsAccuracy = Number(attrs.gps_accuracy);
    const hasCoordinates = Number.isFinite(lat) && Number.isFinite(lon);
    const hasGpsAccuracy = Number.isFinite(gpsAccuracy);
    return hasCoordinates && (!hasGpsAccuracy || gpsAccuracy <= MAX_GPS_ACCURACY_M) ? { lat, lon } : null;
}

function mergeWithIcloudFallback(primary, fallback) {
    // The companion-app tracker (primary) can get stuck reporting a stale
    // "home" fix if iOS suspends background updates. The iCloud (Find My)
    // tracker polls independently, so when both have reliable coordinates,
    // trust whichever one is farther from home.
    const primaryCoords = reliableCoords(primary);
    const fallbackCoords = reliableCoords(fallback);
    if (primaryCoords && fallbackCoords) {
        const primaryDistance = distanceMeters(HOME_LAT, HOME_LON, primaryCoords.lat, primaryCoords.lon);
        const fallbackDistance = distanceMeters(HOME_LAT, HOME_LON, fallbackCoords.lat, fallbackCoords.lon);
        return fallbackDistance > primaryDistance ? fallback : primary;
    }
    if (primaryCoords) return primary;
    if (fallbackCoords) return fallback;
    if (primary?.state === "home" && fallback?.state === "not_home") return fallback;
    return primary;
}

function isAway(entity) {
    const distance = distanceFromHome(entity);
    if (distance !== null) {
        return distance > ARM_DISTANCE_M;
    }
    return entity?.state === "not_home";
}

const gabriel = mergeWithIcloudFallback(msg.payload?.gabriel, msg.payload?.gabriel_icloud);
const valeria = mergeWithIcloudFallback(msg.payload?.valeria, msg.payload?.valeria_icloud);

const awayEntities = [];
for (const [name, entity] of Object.entries({
    gabriel,
    valeria,
    creta: msg.payload?.creta,
})) {
    if (isAway(entity)) {
        awayEntities.push(name);
    }
}

msg.payload.refresh_allowed = awayEntities.length > 0;
msg.payload.refresh_away_entities = awayEntities;

const cretaDistance = distanceFromHome(msg.payload?.creta);
const cretaNearby = cretaDistance !== null && cretaDistance <= KIA_NEARBY_DISTANCE_M;
const cretaAway = awayEntities.includes("creta");

const lastKiaRefresh = flow.get(KIA_LAST_REFRESH_KEY) ?? 0;
const dueForPeriodicRefresh = (Date.now() - lastKiaRefresh) >= KIA_REFRESH_INTERVAL_MS;
const shouldRefreshKia = awayEntities.length > 0 && (dueForPeriodicRefresh || (cretaAway && cretaNearby));

// KIA_LAST_REFRESH_KEY is now set by sec_creta_refresh_ack, only once the
// button.press call actually succeeds. Setting it here unconditionally used
// to "consume" the 5-minute cooldown even when HA was unreachable (e.g.
// mid-restart), so a failed refresh would silently block retries for 5
// minutes instead of retrying on the next 1-minute tick.

return [
    msg,
    awayEntities.length > 0 ? msg : null,
    shouldRefreshKia ? msg : null,
];

// Only reached when button.press on button.creta_force_refresh actually
// succeeded. Marking the cooldown here (instead of optimistically before
// dispatch) means a failed call - e.g. HA unreachable mid-restart - leaves
// the cooldown untouched, so the next 1-minute tick retries immediately.
flow.set("sec_kia_last_force_refresh_ts", Date.now());
return null;

const HOME_LAT = -20.310367851039004;
const HOME_LON = -40.317321761139894;
// Portao/entrada, ~168m de HOME_LAT/HOME_LON: usado para acender o
// refletor um pouco antes da chegada em casa (ver sec_detect_arriving_source).
const GATE_LAT = -20.3095;
const GATE_LON = -40.316;
const event = msg.payload?.event;

const ACTIVE_KEY = "refletor_portao_carros_active_by_arrival";
const ARMED_KEY = "refletor_portao_carros_arrival_armed_entities";
const ARRIVAL_DISTANCE_M = 300;
const MAX_GPS_ACCURACY_M = 100;

function distanceMeters(lat1, lon1, lat2, lon2) {
    const toRad = (value) => value * Math.PI / 180;
    const dLat = toRad(lat2 - lat1);
    const dLon = toRad(lon2 - lon1);
    const a = Math.sin(dLat / 2) ** 2 +
        Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
        Math.sin(dLon / 2) ** 2;
    return 6371000 * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

function reliableCoords(entity) {
    const attrs = entity?.attributes ?? {};
    const lat = Number(attrs.latitude);
    const lon = Number(attrs.longitude);
    const gpsAccuracy = Number(attrs.gps_accuracy);
    const hasCoordinates = Number.isFinite(lat) && Number.isFinite(lon);
    const hasGpsAccuracy = Number.isFinite(gpsAccuracy);
    return hasCoordinates && (!hasGpsAccuracy || gpsAccuracy <= MAX_GPS_ACCURACY_M) ? { lat, lon } : null;
}

function mergeWithIcloudFallback(primary, fallback) {
    // Same rationale as sec_refresh_anyone_away: prefer whichever tracker
    // (companion app vs iCloud/Find My) reports the greater distance from
    // home, since a stuck companion-app fix is the common failure mode.
    const primaryCoords = reliableCoords(primary);
    const fallbackCoords = reliableCoords(fallback);
    if (primaryCoords && fallbackCoords) {
        const primaryDistance = distanceMeters(HOME_LAT, HOME_LON, primaryCoords.lat, primaryCoords.lon);
        const fallbackDistance = distanceMeters(HOME_LAT, HOME_LON, fallbackCoords.lat, fallbackCoords.lon);
        return fallbackDistance > primaryDistance ? fallback : primary;
    }
    if (primaryCoords) return primary;
    if (fallbackCoords) return fallback;
    if (primary?.state === "home" && fallback?.state === "not_home") return fallback;
    return primary;
}

function position(entity) {
    const attrs = entity?.attributes ?? {};
    const lat = Number(attrs.latitude);
    const lon = Number(attrs.longitude);
    const gpsAccuracy = Number(attrs.gps_accuracy);
    const hasCoordinates = Number.isFinite(lat) && Number.isFinite(lon);
    const hasGpsAccuracy = Number.isFinite(gpsAccuracy);
    const reliableCoordinates = hasCoordinates && (!hasGpsAccuracy || gpsAccuracy <= MAX_GPS_ACCURACY_M);

    return {
        entity_id: entity?.entity_id,
        state: entity?.state,
        latitude: hasCoordinates ? lat : null,
        longitude: hasCoordinates ? lon : null,
        gps_accuracy: hasGpsAccuracy ? gpsAccuracy : null,
        location_reliable: reliableCoordinates,
        distance_m: reliableCoordinates ? Math.round(distanceMeters(HOME_LAT, HOME_LON, lat, lon)) : null,
        gate_distance_m: reliableCoordinates ? Math.round(distanceMeters(GATE_LAT, GATE_LON, lat, lon)) : null,
    };
}

function isHome(item) {
    if (item.distance_m !== null) {
        return item.distance_m <= ARRIVAL_DISTANCE_M;
    }
    if (item.gps_accuracy !== null && item.gps_accuracy > MAX_GPS_ACCURACY_M) {
        return false;
    }
    return item.state === "home";
}

const gabriel = position(mergeWithIcloudFallback(msg.payload?.gabriel, msg.payload?.gabriel_icloud));
const valeria = position(mergeWithIcloudFallback(msg.payload?.valeria, msg.payload?.valeria_icloud));
const creta = position(msg.payload?.creta);
const sunBelow = msg.payload?.sun?.state === "below_horizon";
const engineOn = msg.payload?.creta_engine?.state === "on";
const lockState = msg.payload?.creta_lock?.state;

msg.payload = {
    event,
    source: msg.payload?.source,
    reason: msg.payload?.reason,
    sun_below_horizon: sunBelow,
    gabriel,
    valeria,
    creta,
    creta_home: isHome(creta),
    creta_engine_on: engineOn,
    creta_lock: lockState,
    active: flow.get(ACTIVE_KEY) === true,
    armed: flow.get(ARMED_KEY) ?? {},
    arriving: [],
};

if (event === "turn_off") {
    return [msg, null, null];
}
if (event === "context_update") {
    return [null, msg, null];
}
if (event === "location_update") {
    return [null, null, msg];
}
return [null, null, null];

const ACTIVE_KEY = "refletor_portao_carros_active_by_arrival";
const ARMED_KEY = "refletor_portao_carros_arrival_armed_entities";

const active = msg.payload?.active ?? flow.get(ACTIVE_KEY) === true;

if (!active) {
    return null;
}

flow.set(ACTIVE_KEY, false);
flow.set(ARMED_KEY, {});
return msg;

const ARMED_KEY = "refletor_portao_carros_arrival_armed_entities";
const ARM_DISTANCE_M = 100;
const ARRIVAL_DISTANCE_M = 300;
const MAX_GPS_ACCURACY_M = 100;

function isAway(item) {
    if (item && item.distance_m !== null) {
        return item.distance_m > ARM_DISTANCE_M;
    }
    return item?.state === "not_home";
}

function isHome(item) {
    if (item && item.distance_m !== null) {
        return item.distance_m <= ARRIVAL_DISTANCE_M;
    }
    if (item?.gps_accuracy !== null && item?.gps_accuracy > MAX_GPS_ACCURACY_M) {
        return false;
    }
    return item?.state === "home";
}

function updateAwayArming(armed, people) {
    for (const [name, item] of Object.entries(people)) {
        if (isAway(item)) {
            armed[name] = true;
        }
    }
}

function clearCurrentHomeArming(armed, people) {
    for (const [name, item] of Object.entries(people)) {
        if (isHome(item)) {
            armed[name] = false;
        }
    }
}

const armedEntities = msg.payload.armed ?? {};
const trackedPeople = {
    gabriel: msg.payload.gabriel,
    valeria: msg.payload.valeria,
    creta: msg.payload.creta,
};

updateAwayArming(armedEntities, trackedPeople);
clearCurrentHomeArming(armedEntities, trackedPeople);
flow.set(ARMED_KEY, armedEntities);

return null;

const ARMED_KEY = "refletor_portao_carros_arrival_armed_entities";
const VALERIA_APPROACH_NOTIFY_KEY = "valeria_approaching_gabriel_notified";
const ARM_DISTANCE_M = 100;
const VALERIA_APPROACH_DISTANCE_M = 700;
const VALERIA_APPROACH_RESET_DISTANCE_M = 1000;

function isAway(item) {
    if (item && item.distance_m !== null) {
        return item.distance_m > ARM_DISTANCE_M;
    }
    return item?.state === "not_home";
}

const armedEntities = msg.payload.armed ?? {};
for (const [name, item] of Object.entries({
    gabriel: msg.payload.gabriel,
    valeria: msg.payload.valeria,
    creta: msg.payload.creta,
})) {
    if (isAway(item)) {
        armedEntities[name] = true;
    }
}

msg.payload.armed = armedEntities;
flow.set(ARMED_KEY, armedEntities);

const valeria = msg.payload.valeria;
let notify = null;
if (valeria?.distance_m !== null && valeria.distance_m > VALERIA_APPROACH_RESET_DISTANCE_M) {
    flow.set(VALERIA_APPROACH_NOTIFY_KEY, false);
}

if (
    msg.payload.source === "valeria" &&
    valeria?.distance_m !== null &&
    valeria.distance_m <= VALERIA_APPROACH_DISTANCE_M &&
    valeria.distance_m > 50 &&
    flow.get(VALERIA_APPROACH_NOTIFY_KEY) !== true
) {
    flow.set(VALERIA_APPROACH_NOTIFY_KEY, true);
    notify = {
        payload: {
            valeria_distance_m: valeria.distance_m,
        },
    };
}

return [msg, notify];

const ARMED_KEY = "refletor_portao_carros_arrival_armed_entities";
const ARRIVAL_DISTANCE_M = 300;
const MAX_GPS_ACCURACY_M = 100;

function isHome(item) {
    // Ponto do portao/entrada conta como chegada tambem: fica mais perto da
    // rota de acesso do que HOME_LAT/HOME_LON e acende o refletor um pouco
    // antes de chegar em casa de fato.
    if (item && item.gate_distance_m !== null && item.gate_distance_m <= ARRIVAL_DISTANCE_M) {
        return true;
    }
    if (item && item.distance_m !== null) {
        return item.distance_m <= ARRIVAL_DISTANCE_M;
    }
    if (item?.gps_accuracy !== null && item?.gps_accuracy > MAX_GPS_ACCURACY_M) {
        return false;
    }
    return item?.state === "home";
}

const trackedPeople = {
    gabriel: msg.payload.gabriel,
    valeria: msg.payload.valeria,
    creta: msg.payload.creta,
};
const source = msg.payload.source;
const sourcePosition = trackedPeople[source];
const armedEntities = msg.payload.armed ?? {};

if (!sourcePosition || !isHome(sourcePosition)) {
    flow.set(ARMED_KEY, armedEntities);
    return null;
}

if (armedEntities[source]) {
    msg.payload.arriving = [source];
    msg.payload.arrival_source_type = source === "creta" ? "creta" : "person";
}
armedEntities[source] = false;
msg.payload.armed = armedEntities;
flow.set(ARMED_KEY, armedEntities);

return msg.payload.arriving.length > 0 ? msg : null;

// Same arrival event as sec_check_dark/sec_notify_valeria_approaching, but
// only lets Creta arrivals through - this is the trigger to refresh the
// day-trip-log sensor (a completed trip is exactly what just happened).
// Deliberately NOT tied to the 1-5min location refresh cadence: /tripinfo
// is a separate API call, only worth making once per actual arrival.
return msg.payload?.arrival_source_type === "creta" ? msg : null;

const CRETA_APPROACH_DISTANCE_M = 700;

if (msg.payload?.creta_engine_on === true) {
    msg.payload.engine_gate = "engine_on";
    return msg;
}

const creta = msg.payload?.creta;
const cretaWasAway = msg.payload?.armed?.creta === true;
const cretaDistance = creta?.distance_m;
const cretaNearby = cretaDistance !== null && cretaDistance <= CRETA_APPROACH_DISTANCE_M;

if (cretaWasAway && cretaNearby) {
    msg.payload.engine_gate = "creta_nearby_fallback";
    msg.payload.reason = "arriving_after_dark_creta_nearby";
    return msg;
}

return null;

const ACTIVE_KEY = "refletor_portao_carros_active_by_arrival";
flow.set(ACTIVE_KEY, true);
msg.payload.reason = "arriving_after_dark";
return msg;

// Botoeira: fecha o contato. O TS0001 nao honra on_time, entao o pulso e'
// feito por software: este no liga, o delay+no seguinte desligam.
msg.topic = 'zigbee2mqtt/rele_acionador_portao/set';
msg.payload = JSON.stringify({ state: 'ON' });
return msg;

// Fim do pulso: abre o contato.
msg.topic = 'zigbee2mqtt/rele_acionador_portao/set';
msg.payload = JSON.stringify({ state: 'OFF' });
return msg;
